<script setup lang="ts">
import { Head, Link } from '@inertiajs/vue3';
import { Download, File, FileImage, FileText, FileVideo, FolderOpen, Pencil, Plus, RefreshCw, Trash2, UploadCloud, X } from '@lucide/vue';
import { computed, onMounted, onUnmounted, ref } from 'vue';
import AppShell from '../../Layouts/AppShell.vue';
const items=ref<any[]>([]),loading=ref(true),uploading=ref(false),progress=ref(0),filter=ref('all'),kind=ref('document'),collection=ref('resumes'),selectedFile=ref<File>(),editing=ref<any>(),editForm=ref({title:'',description:'',collection:''}),notice=ref(''),error=ref('');
const collections=['uploads','gallery','highlights','certificates','resumes','medical','identity','contracts'];const filtered=computed(()=>filter.value==='all'?items.value:items.value.filter(item=>item.collection===filter.value));const csrf=()=>document.querySelector<HTMLMetaElement>('meta[name="csrf-token"]')?.content??'';const size=(bytes:number)=>bytes<1048576?`${Math.ceil(bytes/1024)} KB`:`${(bytes/1048576).toFixed(1)} MB`;const date=(value:string)=>new Date(value).toLocaleDateString(undefined,{day:'numeric',month:'short',year:'numeric'});const icon=(item:any)=>item.kind==='image'?FileImage:item.kind==='video'?FileVideo:item.mime_type==='application/pdf'?FileText:File;
const api=async(url:string,options:RequestInit={})=>{const response=await fetch(url,{...options,credentials:'same-origin',headers:{Accept:'application/json','Content-Type':'application/json','X-CSRF-TOKEN':csrf()}});const payload=await response.json();if(!response.ok)throw new Error(payload.message??Object.values(payload.errors??{}).flat().join(' '));return payload.data??payload};
const load=async(quiet=false)=>{if(!quiet)loading.value=true;items.value=await api('/api/v1/media?per_page=50');loading.value=false};
const choose=(file?:File)=>{if(!file)return;selectedFile.value=file;kind.value=file.type.startsWith('image/')?'image':file.type.startsWith('video/')?'video':'document';if(kind.value==='image'&&collection.value==='resumes')collection.value='gallery'};
const upload=async()=>{if(!selectedFile.value)return;uploading.value=true;progress.value=0;error.value='';notice.value='';const body=new FormData();body.append('file',selectedFile.value);body.append('kind',kind.value);body.append('collection',collection.value);try{await new Promise<void>((resolve,reject)=>{const xhr=new XMLHttpRequest();xhr.open('POST','/api/v1/media');xhr.setRequestHeader('Accept','application/json');xhr.setRequestHeader('X-CSRF-TOKEN',csrf());xhr.upload.onprogress=event=>{if(event.lengthComputable)progress.value=Math.round(event.loaded/event.total*100)};xhr.onload=()=>xhr.status>=200&&xhr.status<300?resolve():reject(new Error(xhr.response?JSON.parse(xhr.response).message:'Upload failed.'));xhr.onerror=()=>reject(new Error('Network error during upload.'));xhr.send(body)});notice.value='File uploaded. Processing status will update automatically.';selectedFile.value=undefined;await load(true)}catch(exception:any){error.value=exception.message}finally{uploading.value=false}};
const edit=(item:any)=>{editing.value=item;editForm.value={title:item.title??'',description:item.description??'',collection:item.collection}};const saveEdit=async()=>{const updated=await api(`/api/v1/media/${editing.value.id}`,{method:'PATCH',body:JSON.stringify(editForm.value)});Object.assign(editing.value,updated);editing.value=undefined;notice.value='File details updated.'};const remove=async(item:any)=>{if(!confirm(`Delete ${item.original_name}? This cannot be undone.`))return;error.value='';try{await api(`/api/v1/media/${item.id}`,{method:'DELETE'});items.value=items.value.filter(entry=>entry.id!==item.id)}catch(exception:any){error.value=exception.message}};
let refreshTimer:ReturnType<typeof setInterval>;onMounted(async()=>{await load();refreshTimer=setInterval(()=>{if(items.value.some(item=>['pending','processing'].includes(item.processing_status)))load(true)},5000)});onUnmounted(()=>clearInterval(refreshTimer));
</script>
<template><Head title="Media Library"/><AppShell><main class="media-library"><header><div><span><FolderOpen/> PRIVATE LIBRARY</span><h1>Documents & media</h1><p>Manage your résumés, certificates, profile media, and private sporting documents.</p></div><Link href="/upload">Create a post</Link></header><section class="library-upload"><div><UploadCloud/><span><strong>{{selectedFile?.name||'Choose a file to upload'}}</strong><small>PDF, JPG, PNG, WebP, MP4, MOV or WebM</small></span><label><Plus/>Choose file<input hidden type="file" accept="application/pdf,image/jpeg,image/png,image/webp,video/mp4,video/quicktime,video/webm" @change="choose(($event.target as HTMLInputElement).files?.[0])"/></label></div><div v-if="selectedFile"><label>Category<select v-model="collection"><option v-for="item in collections" :value="item">{{item}}</option></select></label><button :disabled="uploading" @click="upload">{{uploading?`Uploading ${progress}%`:'Upload file'}}</button></div><i v-if="uploading"><span :style="{width:`${progress}%`}"/></i></section><p v-if="notice" class="edit-message success">{{notice}}</p><p v-if="error" class="edit-message error">{{error}}</p><nav class="library-filters"><button v-for="item in ['all',...collections]" :class="{active:filter===item}" @click="filter=item">{{item}} <b>{{item==='all'?items.length:items.filter(file=>file.collection===item).length}}</b></button><button @click="load()"><RefreshCw/>Refresh</button></nav><p v-if="loading" class="library-empty">Loading your files…</p><section v-else-if="filtered.length" class="library-grid"><article v-for="item in filtered" :key="item.id"><div class="library-file-icon"><component :is="icon(item)"/></div><div><strong>{{item.title||item.original_name}}</strong><small>{{item.original_name}} · {{size(item.size_bytes)}}</small><span>{{item.collection}}</span><p v-if="item.description">{{item.description}}</p></div><i :class="`processing-${item.processing_status}`">{{item.processing_status}}</i><i :class="`moderation-${item.moderation_status}`">{{item.moderation_status}}</i><footer><small>{{date(item.created_at)}}</small><a :href="item.download_url" title="Download"><Download/></a><button title="Edit details" @click="edit(item)"><Pencil/></button><button title="Delete" @click="remove(item)"><Trash2/></button></footer><p v-if="item.processing_error" class="file-error">{{item.processing_error}}</p></article></section><section v-else class="library-empty"><FolderOpen/><h2>No files in this category</h2><p>Upload your first document or media file above.</p></section></main><div v-if="editing" class="library-edit-modal" @click.self="editing=undefined"><form @submit.prevent="saveEdit"><button type="button" @click="editing=undefined"><X/></button><h2>Edit file details</h2><label>Display title<input v-model="editForm.title" maxlength="160"/></label><label>Category<select v-model="editForm.collection"><option v-for="item in collections" :value="item">{{item}}</option></select></label><label>Description<textarea v-model="editForm.description" maxlength="2000"/></label><button>Save changes</button></form></div></AppShell></template>
